const fs = require\('fs'\);
const html = fs.readFileSync\('genesis-3d.html', 'utf8'\);
const start = html.indexOf\('<script>'\);
const end = html.lastIndexOf\('</script>'\);
const js = html.slice\(start+8, end\);
const lines = js.split\('\\n'\);
console.log\('Total JS lines:', lines.length\);
function check\(s, e\) {
  const slice = lines.slice\(s, e\).join\('\\n'\);
  try { new Function\(slice\); return true; } catch\(err\) { return false; }
}
let lo=0, hi=lines.length;
while\(lo+1 < hi\) {
  const mid = \(lo+hi\)>>1;
  if \(!check\(0, mid\)\) hi=mid; else lo=mid;
}
console.log\('Error near script line', hi\);
console.log\(lines.slice\(Math.max\(0,hi-3\), hi+3\).join\('\\n'\)\);
" 2>&1)

