const fs = require\('fs'\);
const js = fs.readFileSync\('/tmp/genesis_check.mjs', 'utf8'\);
const lines = js.split\('\\n'\).slice\(0, 648\);
// Count backticks per line \(non-escaped\)
for \(let i = 0; i < lines.length; i++\) {
  const line = lines[i];
  let count = 0;
  for \(let j = 0; j < line.length; j++\) {
    if \(line[j] === '\\`' && \(j === 0 || line[j-1] !== '\\\\\\\\'\)\) count++;
  }
  if \(count % 2 !== 0\) {
    console.log\('Odd backticks on line', i+1, ':', count, '|', line.trim\(\).substring\(0,80\)\);
  }
}
console.log\('Done'\);
")

